import { access, lstat, mkdir, symlink, cp, unlink, rm, writeFile } from "node:fs/promises";
import type { Stats } from "node:fs";
import path from "node:path";
import { AGENT_REGISTRY_BY_ID } from "../config/agents.ts";
import { resolveAgentSkillPath, getDeployMethod } from "./resolve.ts";
import { UserError } from "../errors.ts";
import type { AgentId, DeployAction, Manifest } from "../types.ts";
import { logger } from "../logger.ts";

export function planDeploy(
  manifest: Manifest,
  sourceDir: string,
  detectedAgents: AgentId[],
  home: string
): DeployAction[] {
  const method = getDeployMethod();
  const actions: DeployAction[] = [];
  const resolvedSourceDir = path.resolve(sourceDir);

  for (const skill of manifest.skills) {
    const source = path.resolve(sourceDir, skill.path);

    if (source !== resolvedSourceDir && !source.startsWith(resolvedSourceDir + path.sep)) {
      throw new UserError(
        "DEPLOY_FAILED",
        `Skill path "${skill.path}" resolves outside the repository root: ${source}`
      );
    }

    for (const agentId of skill.agents) {
      if (!detectedAgents.includes(agentId)) continue;

      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;

      const target = resolveAgentSkillPath(agent, skill.name, home);

      actions.push({ skill: skill.name, agent: agentId, source, target, method });
    }
  }

  return actions;
}

export async function executeDeploy(
  actions: DeployAction[],
  dryRun: boolean,
  verbose: boolean
): Promise<{ succeeded: number; failed: Array<{ action: DeployAction; error: string }> }> {
  let succeeded = 0;
  const failed: Array<{ action: DeployAction; error: string }> = [];

  for (const action of actions) {
    const label = `${action.skill} -> ${action.agent}`;

    try {
      await access(action.source);
    } catch {
      const msg = `Source not found: ${action.source}`;
      failed.push({ action, error: msg });
      logger.fail(label, msg);
      continue;
    }

    if (dryRun) {
      logger.plan(label);
      if (verbose) {
        logger.detail(`${action.method}: ${action.source} -> ${action.target}`);
      }
      succeeded++;
      continue;
    }

    try {
      await removeExisting(action.target, verbose);
      await mkdir(path.dirname(action.target), { recursive: true });

      if (action.method === "symlink") {
        await symlink(action.source, action.target, "dir");
      } else {
        await cp(action.source, action.target, { recursive: true });
        await writeFile(path.join(action.target, ".inception-marker"), "inception-engine\n");
      }

      logger.ok(label);
      if (verbose) {
        logger.detail(`${action.method}: ${action.source} -> ${action.target}`);
      }
      succeeded++;
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      failed.push({ action, error: msg });
      logger.fail(label, msg);
    }
  }

  return { succeeded, failed };
}

async function removeExisting(targetPath: string, verbose: boolean): Promise<void> {
  let stat: Stats;
  try {
    stat = await lstat(targetPath);
  } catch {
    return;
  }

  if (stat.isSymbolicLink()) {
    if (verbose) {
      logger.detail(`removing existing symlink: ${targetPath}`);
    }
    await unlink(targetPath);
  } else {
    if (verbose) {
      logger.warn(targetPath, "replacing existing directory");
    }
    await rm(targetPath, { recursive: true });
  }
}

import { access, lstat, unlink, rm, readlink } from "node:fs/promises";
import path from "node:path";
import { AGENT_REGISTRY_BY_ID } from "../config/agents.ts";
import { resolveAgentSkillPath } from "./resolve.ts";
import type { AgentId, Manifest, RevertAction } from "../types.ts";
import { logger } from "../logger.ts";

export function planRevert(
  manifest: Manifest,
  detectedAgents: AgentId[],
  home: string
): RevertAction[] {
  const actions: RevertAction[] = [];

  for (const skill of manifest.skills) {
    for (const agentId of skill.agents) {
      if (!detectedAgents.includes(agentId)) continue;

      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;

      const target = resolveAgentSkillPath(agent, skill.name, home);
      actions.push({ skill: skill.name, agent: agentId, target });
    }
  }

  return actions;
}

export async function executeRevert(
  actions: RevertAction[],
  dryRun: boolean,
  verbose: boolean
): Promise<{ succeeded: number; skipped: number }> {
  let succeeded = 0;
  let skipped = 0;

  for (const action of actions) {
    const label = `${action.skill} -> ${action.agent}`;

    let stat: Awaited<ReturnType<typeof lstat>>;
    try {
      stat = await lstat(action.target);
    } catch {
      logger.skip(label, "(not found, skipping)");
      skipped++;
      continue;
    }

    if (!(await isOwnedByInceptionEngine(action.target, stat))) {
      logger.warn(label, `skipping: ${action.target} does not have inception-engine ownership proof — not managed by inception-engine`);
      skipped++;
      continue;
    }

    if (dryRun) {
      logger.plan(label);
      if (verbose) {
        logger.detail(`would remove: ${action.target}`);
      }
      succeeded++;
      continue;
    }

    try {
      if (stat.isSymbolicLink()) {
        await unlink(action.target);
      } else {
        await rm(action.target, { recursive: true });
      }
      logger.ok(label);
      if (verbose) {
        logger.detail(`removed: ${action.target}`);
      }
      succeeded++;
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      logger.fail(label, msg);
    }
  }

  return { succeeded, skipped };
}

async function isOwnedByInceptionEngine(
  targetPath: string,
  stat: Awaited<ReturnType<typeof lstat>>
): Promise<boolean> {
  if (stat.isSymbolicLink()) {
    try {
      const linkTarget = await readlink(targetPath);
      const resolved = path.resolve(path.dirname(targetPath), linkTarget);
      await access(path.join(resolved, "SKILL.md"));
      return true;
    } catch {
      return false;
    }
  } else {
    try {
      await access(path.join(targetPath, ".inception-marker"));
      return true;
    } catch {
      return false;
    }
  }
}

